import json
with open('baseline-packages.json') as f: base = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

def get_pkgs(data):
    result = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-1]
        for fw in proj['frameworks']:
            for pkg in fw.get('topLevelPackages', []):
                result[(name, pkg['id'])] = pkg['resolvedVersion']
    return result

b, a = get_pkgs(base), get_pkgs(after)
changes = [(k, b[k], a[k]) for k in b if k in a and b[k] != a[k]]
added = [(k, a[k]) for k in a if k not in b]
removed = [(k, b[k]) for k in b if k not in a]

if not changes and not added and not removed:
    print('✅ Conversion is fully version-neutral. All packages resolve identically.')
else:
    for c in changes: print(f'CHANGED: {c[0]} {c[1]} -> {c[2]}')
    for a_ in added: print(f'ADDED: {a_}')
    for r in removed: print(f'REMOVED: {r}')
"

